```csharp
using System;
using System.Linq;
using System.Reflection;

public abstract class BaseRepository<TEntity> where TEntity : class
{
    protected readonly DbContext _context;

    public BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual TEntity GetById(object id)
    {
        return _context.Set<TEntity>().Find(id);
    }

    public virtual TEntity FindByDynamic(object criteria)
    {
        // Use reflection to get the property name and value from the criteria object
        var propertyInfo = criteria.GetType().GetProperty("PropertyName");
        var value = criteria.GetType().GetProperty("Value").GetValue(criteria);

        // Use the property name and value to build a lambda expression
        var parameter = Expression.Parameter(typeof(TEntity));
        var memberExpression = Expression.Property(parameter, propertyInfo.Name);
        var constantExpression = Expression.Constant(value);
        var lambdaExpression = Expression.Equal(memberExpression, constantExpression);

        // Use the lambda expression to filter the entities
        var query = _context.Set<TEntity>().AsQueryable();
        var result = query.Where(Expression.Lambda<Func<TEntity, bool>>(lambdaExpression, parameter)).FirstOrDefault();

        return result;

